export const TYPEN = ["Ökodorf", "Kommune", "Kollektiv", "Spirituelle Gemeinschaft", "Wohnprojekt"]

export function getTypBadge(typ) {
  const map = {
    "Ökodorf": "badge-oeko",
    "Kommune": "badge-kommune",
    "Kollektiv": "badge-kollektiv",
    "Spirituelle Gemeinschaft": "badge-spirituell",
    "Wohnprojekt": "badge-wohn",
  }
  return map[typ] || "badge-oeko"
}

export function getStatusInfo(status) {
  const map = {
    "aktiv": { label: "Aktiv auf Communet", color: "#2d6a4f", bg: "#e8f5ee", icon: "🟢" },
    "einrichtung": { label: "Profil in Einrichtung", color: "#7c4a0a", bg: "#fff3e0", icon: "🟡" },
    "nicht-registriert": { label: "Noch nicht registriert", color: "#6b6b63", bg: "#f0f0ee", icon: "⚫" },
  }
  return map[status] || map["nicht-registriert"]
}

